import React, { useState } from "react";
import Marquee from "react-fast-marquee";
import img1 from "./images/01.png";
import img2 from "./images/02.png";
import img3 from "./images/03.png";
import "./App.css";

function MarqueeExample() {
  const [isHovered, setIsHovered] = useState(false);

  function handleClick(imageIndex) {
    switch (imageIndex) {
      case 0:
        window.location.href = "page1.html";
        break;
      case 1:
        window.location.href = "page2.html";
        break;
      case 2:
        window.location.href = "page3.html";
        break;
      default:
        break;
    }
  }
  // Get all marquee items
  const marqueeItems = document.querySelectorAll(".marquee-item");

  // Loop through each marquee item
  marqueeItems.forEach((item) => {
    // Get the box element
    const box = item.querySelector(".marquee-item-box");
    // Add a hover event listener to the box
    box.addEventListener("mouseover", () => {
      // Add the hover-stop class to the marquee item
      item.classList.add("hover-stop");
    });
    // Add a mouseout event listener to the box
    box.addEventListener("mouseout", () => {
      // Remove the hover-stop class from the marquee item
      item.classList.remove("hover-stop");
    });
  });

  return (
    <div className="marquee-container">
      <Marquee
        gradient={false}
        speed={40}
        direction="up"
        stop={isHovered}
        onMouseEnter={() => setIsHovered(true)}
        onMouseLeave={() => setIsHovered(false)}
      >
        <div
          className="marquee-item"
          onMouseEnter={() => setIsHovered(true)}
          onMouseLeave={() => setIsHovered(false)}
        >
          <div className="marquee-item-box">
            <img src={img1} alt="example" />
            <span>
              Lorem ipsum dolor sit amet, consectetur adipiscing elit.
            </span>
          </div>
        </div>
        <div
          className="marquee-item"
          onMouseEnter={() => setIsHovered(true)}
          onMouseLeave={() => setIsHovered(false)}
        >
          <div className="marquee-item-box">
            <img src={img2} alt="example" />
            <span>
              Sed do eiusmod tempor incididunt ut labore et dolore magna aliqua.
            </span>
          </div>
        </div>
        <div
          className="marquee-item"
          onMouseEnter={() => setIsHovered(true)}
          onMouseLeave={() => setIsHovered(false)}
        >
          <div className="marquee-item-box">
            <img src={img3} alt="example" />
            <span>
              Sed do eiusmod tempor incididunt ut labore et dolore magna aliqua.
            </span>
          </div>
        </div>
      </Marquee>
    </div>
  );
}

export default MarqueeExample;
